import React, { useEffect, useState } from 'react';
import { View, Text, StyleSheet, TouchableOpacity, ActivityIndicator, ScrollView } from 'react-native';
import { LinearGradient } from 'expo-linear-gradient';
import { useSelector } from 'react-redux';
import { RootState } from '../../features/store';

interface JourneyMission {
  id: string;
  created_at: string;
  completed: boolean;
  journeyId: string;
  challengeId: string;
  userId: string | null;
  journeys: {
    description: string;
  };
  challenges: {
    title: string;
    description: string;
  };
  user: string | null;
}

const MissionsScreen = ({ route }: any) => {
  const { journeyId } = route.params;
  const [journeyMissions, setJourneyMissions] = useState<JourneyMission[]>([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);
  const [updatingMission, setUpdatingMission] = useState<string | null>(null);
  const { user } = useSelector((state: RootState) => state.auth);

  useEffect(() => {
    const fetchMissions = async () => {
      if (!user?.id || !journeyId) return;

      try {
        const response = await fetch(`http://localhost:5000/api/journeysMissions/journey/${journeyId}`);
        const data = await response.json();

        if (!response.ok) {
          throw new Error('Error al obtener las misiones');
        }

        console.log('Misiones del viaje:', data);
        setJourneyMissions(data || []);
      } catch (err: any) {
        console.error('Error al obtener las misiones:', err.message);
        setError(err.message);
      } finally {
        setLoading(false);
      }
    };

    fetchMissions();
  }, [user, journeyId]);

  if (loading) {
    return (
      <View style={styles.container}>
        <ActivityIndicator size="large" color="#0000ff" />
        <Text>Cargando misiones...</Text>
      </View>
    );
  }

  if (error) {
    return (
      <View style={styles.container}>
        <Text style={styles.errorText}>Error: {error}</Text>
      </View>
    );
  }

  return (
    <ScrollView style={styles.container}>
      <LinearGradient
        colors={['#4CAF50', '#2E7D32']}
        style={styles.header}
      >
        <Text style={styles.headerTitle}>Misiones del Viaje</Text>
      </LinearGradient>

      {journeyMissions.map((mission) => (
        <View key={mission.id} style={styles.missionCard}>
          <LinearGradient
            colors={['#ffffff', '#f8f8f8']}
            style={styles.cardGradient}
          >
            <Text style={styles.missionTitle}>{mission.challenges?.title || 'Sin título'}</Text>
            <Text style={styles.statusBadge}>
              {mission.completed ? '✓ Completada' : '⏳ Pendiente'}
            </Text>

            <Text style={styles.dateText}>
              {new Date(mission.created_at).toLocaleDateString()}
            </Text>
          </LinearGradient>
        </View>
      ))}
    </ScrollView>
  );
};

const styles = StyleSheet.create({
  container: {
    flex: 1,
    backgroundColor: '#f5f5f5',
  },
  header: {
    padding: 24,
    paddingTop: 40,
    borderBottomLeftRadius: 30,
    borderBottomRightRadius: 30,
    marginBottom: 20,
  },
  headerTitle: {
    fontSize: 28,
    fontWeight: 'bold',
    color: '#FFFFFF',
    textAlign: 'center',
  },
  missionCard: {
    margin: 16,
    borderRadius: 16,
    overflow: 'hidden',
    backgroundColor: '#FFF',
    shadowColor: '#000',
    shadowOffset: { width: 0, height: 2 },
    shadowOpacity: 0.1,
    shadowRadius: 8,
    elevation: 3,
  },
  cardGradient: {
    padding: 16,
  },
  missionTitle: {
    fontSize: 18,
    fontWeight: 'bold',
    color: '#2E7D32',
  },
  statusBadge: {
    fontSize: 12,
    color: '#666',
  },
  dateText: {
    fontSize: 12,
    color: '#666',
  },
  errorText: {
    fontSize: 16,
    color: '#D32F2F',
    textAlign: 'center',
  },
});

export default MissionsScreen;
